.darma-loader-darma-custom-018 {
  width: 60px;
  aspect-ratio: 1;
  background: linear-gradient(90deg, var(--loader-color, #CEE879) 50%, var(--loader-secondary-color, #FF5254) 0) top / 100% 50% no-repeat, linear-gradient(90deg, #FCB653 50%, #5CACC4 0);
  -webkit-mask: linear-gradient(#000 0 0) 0 0 / 50% 50% no-repeat;
  animation: darma-loader-darma-custom-018-l18 2s infinite;
}
@keyframes darma-loader-darma-custom-018-l18 {
  0% { -webkit-mask-position: 0 0; }
  25% { -webkit-mask-position: 100% 0; }
  50% { -webkit-mask-position: 100% 100%; }
  75% { -webkit-mask-position: 0 100%; }
  100% { -webkit-mask-position: 0 0; }
}

